+		for _, item := range rmsList.Items {
+			specMap, _ := item.Object["spec"].(map[string]any)
+			statusMap, _ := item.Object["status"].(map[string]any)
+
+			t := kagentCRDTool{
+				Name:      item.GetName(),
+				Namespace: item.GetNamespace(),
+				Cluster:   cluster,
+				Kind:      "RemoteMCPServer",
+			}
+			if specMap != nil {
+				t.URL = nestedString(specMap, "url")
